// Validate and normalize incoming lead data
const data = $input.first().json.body || $input.first().json;

// Extract fields with fallbacks
const name = (data.name || data.full_name || data.firstName + ' ' + data.lastName || '').trim();
const email = (data.email || data.email_address || '').toLowerCase().trim();
const phone = (data.phone || data.phone_number || data.tel || '').trim();
const message = (data.message || data.notes || data.comment || '').trim();
const source = (data.source || data.utm_source || data.referrer || 'Unknown').trim();
const company = (data.company || data.business || data.organization || '').trim();

// Basic email validation
const emailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

if (!emailValid) {
  throw new Error(`Invalid email address: ${email}`);
}

if (!name) {
  throw new Error('Name is required');
}

// Score lead (0-100) based on completeness
let score = 50; // base score
if (phone) score += 15;
if (message && message.length > 20) score += 20;
if (company) score += 15;

const timestamp = new Date().toISOString();
const leadId = 'LEAD-' + Date.now();

return [{
  json: {
    leadId,
    name,
    email,
    phone,
    message,
    source,
    company,
    score,
    status: 'New',
    createdAt: timestamp,
    rawData: data
  }
}];
